import pytest

from palindrome import is_palindrome


class TestIsPalindromeHappyPath:
    """Tests for standard palindrome cases."""

    def test_simple_palindrome(self):
        assert is_palindrome("racecar") is True

    def test_palindrome_lowercase(self):
        assert is_palindrome("level") is True

    def test_palindrome_mixed_case(self):
        assert is_palindrome("Racecar") is True

    def test_palindrome_with_spaces(self):
        assert is_palindrome("race car") is True

    def test_palindrome_multiple_words(self):
        assert is_palindrome("a man a plan a canal panama") is True

    def test_palindrome_with_punctuation(self):
        assert is_palindrome("madam, i'm adam") is True


class TestIsPalindromeEdgeCases:
    """Tests for edge cases and boundary conditions."""

    def test_empty_string(self):
        assert is_palindrome("") is True

    def test_single_character(self):
        assert is_palindrome("a") is True

    def test_two_identical_characters(self):
        assert is_palindrome("aa") is True

    def test_single_space(self):
        assert is_palindrome(" ") is True

    def test_palindrome_numbers_as_string(self):
        assert is_palindrome("12321") is True

    def test_palindrome_with_numbers_and_letters(self):
        assert is_palindrome("a1a") is True


class TestIsPalindromeNonPalindromes:
    """Tests for inputs that are NOT palindromes."""

    def test_simple_non_palindrome(self):
        assert is_palindrome("hello") is False

    def test_different_characters(self):
        assert is_palindrome("abc") is False

    def test_two_different_characters(self):
        assert is_palindrome("ab") is False

    def test_almost_palindrome(self):
        assert is_palindrome("hello") is False

    def test_non_palindrome_with_spaces(self):
        assert is_palindrome("hello world") is False


class TestIsPalindromeErrorCases:
    """Tests for error cases and unexpected input types."""

    def test_none_input_raises_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(None)

    def test_numeric_input_returns_expected_result(self):
        # Numbers should be treated as strings
        assert is_palindrome(123) is False  # raises TypeError on .lower()

    def test_list_input_raises_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(["a", "b"])

    def test_whitespace_only_multiple_spaces(self):
        assert is_palindrome("   ") is True
